import{_ as t,o as a,c as o,a0 as i}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"NEXUS Documentation Routine","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/DOCUMENTATION_ROUTINE.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/DOCUMENTATION_ROUTINE.md","lastUpdated":1783623176000}'),r={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/DOCUMENTATION_ROUTINE.md"};function n(c,e,d,s,l,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="nexus-documentation-routine" tabindex="-1">NEXUS Documentation Routine <a class="header-anchor" href="#nexus-documentation-routine" aria-label="Permalink to &quot;NEXUS Documentation Routine&quot;">​</a></h1><p>To prevent semantic drift, codebase clutter, and knowledge loss, all NEXUS documentation must adhere to the following rigorous routine.</p><h2 id="_1-the-single-source-of-truth" tabindex="-1">1. The Single Source of Truth <a class="header-anchor" href="#_1-the-single-source-of-truth" aria-label="Permalink to &quot;1. The Single Source of Truth&quot;">​</a></h2><ul><li><strong>VitePress is the Official Portal:</strong> All functional documentation, guides, and deep-dives live under <code>docs/guide/</code>, <code>docs/architecture/</code>, and <code>docs/deep-dive/</code>.</li><li><strong>No Loose Markdown Files:</strong> Do not drop <code>.md</code> files in the root <code>docs/</code> directory. If it belongs in the wiki, put it in the VitePress structure. If it is an obsolete report, put it in <code>docs/archive/</code>.</li></ul><h2 id="_2-architectural-decisions-adrs" tabindex="-1">2. Architectural Decisions (ADRs) <a class="header-anchor" href="#_2-architectural-decisions-adrs" aria-label="Permalink to &quot;2. Architectural Decisions (ADRs)&quot;">​</a></h2><ul><li>Every major architectural decision must be recorded as an ADR in <code>docs/adr/</code>.</li><li>Use <code>docs/adr/template.md</code> for new decisions.</li><li>Never modify an accepted ADR; if a decision changes, create a new ADR that supersedes the old one.</li></ul><h2 id="_3-canonical-invariants" tabindex="-1">3. Canonical Invariants <a class="header-anchor" href="#_3-canonical-invariants" aria-label="Permalink to &quot;3. Canonical Invariants&quot;">​</a></h2><ul><li>The <code>CANONICAL_*.md</code> files (e.g., <code>CANONICAL_ARCHITECTURE.md</code>, <code>CANONICAL_RUNTIME.md</code>) are the ultimate truth for the system&#39;s invariants.</li><li>If you refactor a core subsystem (T1-T6), you <strong>MUST</strong> update the canonical definitions.</li></ul><h2 id="_4-archival-and-deprecation" tabindex="-1">4. Archival and Deprecation <a class="header-anchor" href="#_4-archival-and-deprecation" aria-label="Permalink to &quot;4. Archival and Deprecation&quot;">​</a></h2><ul><li>Old reports, experiments, draft plans, and handover notes go to <code>docs/archive/</code>.</li><li>Do not delete historical context (like <code>docs/research/</code>), but ensure it is separated from the active operational documentation.</li></ul><h2 id="_5-automated-generation" tabindex="-1">5. Automated Generation <a class="header-anchor" href="#_5-automated-generation" aria-label="Permalink to &quot;5. Automated Generation&quot;">​</a></h2><ul><li>Documentation for the API endpoints and database schemas should be synced automatically where possible, but context and &quot;why&quot; must be manually curated in the VitePress deep-dives.</li></ul><p><strong>Motto</strong>: <em>If it is not in the VitePress sidebar or an ADR, it does not exist.</em></p>',13)])])}const _=t(r,[["render",n]]);export{m as __pageData,_ as default};
